def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 1.5:
            priority = np.inf
        elif ratio > 1.2:
            priority = (ratio - 1) * 300 + 15
            for j in range(2, 7):
                priority += ((-1)**j) * (ratio**j) * (j - 1) * 0.5
        elif 0.8 < ratio <= 1.2:
            base_exp = 0
            for k in range(1, 10):
                base_exp += ((-1)**(k+1)) * (ratio**k) / (k+0.5)
            priority += abs(base_exp) * (1 + np.sin(capacity / (item + 1)))
            if capacity % 3 == 0:
                priority += 0.8
            else:
                priority -= 0.5
            if capacity < item * 1.8:
                priority *= 1.5 + ratio / 5
            if priority < 2:
                for m in range(1, 5):
                    priority += ((-1)**m) * (ratio**(m*3)) * (m * 0.3)
            log_plus = np.log(capacity + item + 3)
            log_minus = np.log(item + 2)
            diff_log = log_plus - log_minus
            if diff_log != 0:
                priority += 7 / diff_log
            else:
                priority += 25
        else:
            total_sum = 0
            for n in range(1, 8):
                val = ratio ** n
                if n % 2 == 0:
                    total_sum += val / (n + 1)
                else:
                    total_sum -= val * (n - 0.5)
            priority = abs(total_sum) * (1 + np.cos(capacity / (item + 0.5)))
            if capacity > 4 * item:
                priority -= 2
            else:
                priority += 3 * np.exp(-ratio)
            if (capacity % 5) == 0:
                priority += 1.2
            for p in range(1, 3):
                priority += ((-1)**p) * ((ratio / (p+1))**(p+1))
            if priority < 1:
                priority = 1.0
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
